proof_block:
// Re-reveal the opaque spec fns so each conjunct of the post-conditions
// becomes visible to z3 before the body's own reveals run (reveal is
// idempotent). The post-conditions of `next_set_request_postconditions`
// can only be exploited once their opaque definition has been unfolded.
reveal(HostState::next_set_request_postconditions);
reveal(HostState::next_set_request_preconditions);
reveal(HostState::host_state_common_postconditions);
reveal(HostState::host_state_common_preconditions);
reveal(HostState::host_state_packet_preconditions);

// The ensures-clause is an implication, so its antecedent is NOT in
// scope as a hypothesis; we have to wrap our extraction in an `if` that
// matches the implication's antecedent. Inside that branch, the conjuncts
// of both post-conditions become available facts.
if post1_self_.next_set_request_postconditions(pre_self_, r1@)
    && post2_self_.next_set_request_postconditions(pre_self_, r2@)
{
    // The precondition forces pre_self_.received_packet to be Some (its
    // `host_state_common_preconditions` body is `match ... { None => false, ... }`),
    // so on both sides the `match` arm of next_set_request_postconditions
    // selects `Some(cpacket)`. Binding the shared cpacket once makes the
    // subsequent triggers fire on both runs simultaneously.
    assert(pre_self_.received_packet is Some);
    let cp = pre_self_.received_packet.unwrap();

    // Local shorthand for the abstracted send-set on each side. These
    // are the exact `out` arguments the spec uses; pinning the names lets
    // both `next_set_request` triggers fire across the two runs.
    let out1: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@);
    let out2: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@);

    // Lift the high-level abstract transition into scope on each side. Without
    // these asserts z3 keeps the `match` blob unsplit and never instantiates
    // the SetRequest conjuncts.
    assert(next_set_request(pre_self_@, post1_self_@, cp@, out1));
    assert(next_set_request(pre_self_@, post2_self_@, cp@, out2));

    // `next_set_request` directly pins these two AbstractHostState fields to
    // pre on each side, so they must agree across the two runs.
    assert(post1_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post2_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post1_self_@.delegation_map == post2_self_@.delegation_map);
    assert(post1_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post2_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post1_self_@.num_delegations == post2_self_@.num_delegations);

    // `host_state_common_postconditions` pins `constants` (concrete) and
    // through the view definition that lifts to the abstract `constants` field.
    assert(post1_self_.constants == pre_self_.constants);
    assert(post2_self_.constants == pre_self_.constants);
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(post2_self_@.constants == pre_self_@.constants);
    assert(post1_self_@.constants == post2_self_@.constants);

    // Final conjunct of `next_set_request_postconditions`: received_packet is
    // None after the step. Through the view definition that lifts to the
    // abstract field being None as well.
    assert(post1_self_.received_packet is None);
    assert(post2_self_.received_packet is None);
    assert(post1_self_@.received_packet is None);
    assert(post2_self_@.received_packet is None);
    assert(post1_self_@.received_packet == post2_self_@.received_packet);
}
